it("should return premium 85 G for a single plain staff — 80 G base + 5 G fee", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: [
          { type: "staff", material: "oak", enchantment: 0, cursed: false },
        ],
      },
    ],
  };
  const result = claimOffice(input);
  expect(result).toEqual({ results: [{ premium: 85 }] });
});

